namespace sv_851f7981a924497bb0c3ca332fac5a56.Models;

public class ApplicationFormState
{
    // Step 1 — Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2 — Experience
    public List<JobHistoryEntry> JobHistory { get; set; } = [];

    // Step 3 — References
    public List<ReferenceContact> References { get; set; } = [];

    // Track which steps have been completed
    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class JobHistoryEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_851f7981a924497bb0c3ca332fac5a56.Models;

namespace sv_851f7981a924497bb0c3ca332fac5a56.Services;

/// <summary>
/// Singleton service that stores wizard state keyed by ASP.NET Core session ID.
/// This survives per-page circuit disposal because it lives outside the circuit scope.
/// Each user gets their own state via their unique session ID.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, ApplicationFormState> _store = new();

    public ApplicationFormState GetOrCreate(string sessionId)
    {
        return _store.GetOrAdd(sessionId, _ => new ApplicationFormState());
    }

    public void Remove(string sessionId)
    {
        _store.TryRemove(sessionId, out _);
    }
}

