@inherits LayoutComponentBase
@inject NavigationManager Navigation
@inject WizardStateStore StateStore
@inject IHttpContextAccessor HttpContextAccessor
@using sv_851f7981a924497bb0c3ca332fac5a56.Services
@using sv_851f7981a924497bb0c3ca332fac5a56.Models

<div class="container py-4">
    <h2 class="mb-4">Job Application</h2>

    <div class="d-flex mb-4 gap-2">
        @for (int i = 0; i < _steps.Length; i++)
        {
            var step = i;
            var isCurrent = step + 1 == CurrentStep;
            var isCompleted = _completedSteps.Contains(step + 1);
            <a href="@_steps[step].Url"
               class="btn @(isCurrent ? "btn-primary" : isCompleted ? "btn-success" : "btn-outline-secondary")">
                @((step + 1)). @_steps[step].Label
                @if (isCompleted) { <span>&#10003;</span> }
            </a>
        }
    </div>

    <p class="text-muted">Step @CurrentStep of @_steps.Length</p>

    <hr />

    @Body
</div>

@code {
    private record StepInfo(string Url, string Label);

    private static readonly StepInfo[] _steps =
    [
        new("/apply/personal-info", "Personal Info"),
        new("/apply/experience", "Experience"),
        new("/apply/references", "References"),
        new("/apply/review", "Review"),
    ];

    private HashSet<int> _completedSteps = [];

    private int CurrentStep
    {
        get
        {
            var path = new Uri(Navigation.Uri).AbsolutePath.TrimEnd('/');
            for (int i = 0; i < _steps.Length; i++)
            {
                if (path.Equals(_steps[i].Url, StringComparison.OrdinalIgnoreCase))
                    return i + 1;
            }
            return 1;
        }
    }

    protected override void OnInitialized()
    {
        var sessionId = HttpContextAccessor.HttpContext?.Session.Id;
        if (sessionId is not null)
        {
            _completedSteps = StateStore.GetOrCreate(sessionId).CompletedSteps;
        }
    }
}

